SELECT PEN_SICKNESS_DEDUCTIONS_NEW.PERCENTAGE
FROM PEN_SICKNESS_DEDUCTIONS_NEW
WHERE PEN_SICKNESS_DEDUCTIONS_NEW.DEFAULT_FLG='1';

/*SELECT PEN_OPS.PEN_PREPARE_DAYS.INSHISTYP_TRANS_TYPE, COM_INSURANCE_HISTORY_TYPES.TRANS_DESCR, MIN(nvl(MONTH,12)||'/'||nvl(YEAR,4000)), MAX(nvl(MONTH,1)||'/'||nvl(YEAR,1000)), SUM(NOTICE_INSURANCE_DAYS+NOTICE_INS_DAYS_INCR) FROM PEN_OPS.PEN_PREPARE_DAYS , COM_INSURANCE_HISTORY_TYPES, COM_COVERS_PER_COVERAGES WHERE PEN_OPS.PEN_PREPARE_DAYS.INS_INSURED_ID=:P_INSURED_ID AND PEN_OPS.PEN_PREPARE_DAYS.INSHISTYP_TRANS_TYPE=COM_INSURANCE_HISTORY_TYPES.TRANS_TYPE and COM_COVERS_PER_COVERAGES.COVCOD_COVERAGE_CODE=PEN_PREPARE_DAYS.COVCOD_COVERAGE_CODE and COM_COVERS_PER_COVERAGES.CVR_COVER_CODE='ΚΣΙ' AND ( nvl(NOTICE_INSURANCE_DAYS,0) != 0 OR nvl(NOTICE_INS_DAYS_INCR,0) != 0) AND 1 = CASE WHEN ( ( PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_ORGBRA_CODE_DA = :P_APPL_UNIT_CODE and PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_ORGBRA_CODE_DA IS NOT NULL ) AND ( PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_YEAR_DA = :P_APPL_YEAR and PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_YEAR_DA IS NOT NULL ) AND ( PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_NO_DA = :P_APPL_INCR_SEQ_NO and PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_NO_DA IS NOT NULL ) AND NVL(PEN_PREPARE_DAYS.PARALLEL_FLG,'0') = '0' ) -- DIADOXIKI THEN 1 WHEN NVL(PEN_PREPARE_DAYS.SOURCE_ORIGIN,'2') = 2 -- AFORA PERIPTOSEIS SYGXWNEFTHENTWN APO OTHONH ATHANASIOU and PEN_PREPARE_DAYS.COMMIT_FLG = 2 THEN 1 WHEN NVL(PEN_PREPARE_DAYS.SOURCE_ORIGIN,'2') = '2' and :P_HAS_PREPARE_PROTOCOLS = 0 and PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_ORGBRA_CODE IS NULL and PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_YEAR IS NULL and PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_NO IS NULL -- AYTOMATOPOIHMENES/PISTOPOIHMENOI XVRIS PROTOCOLS THEN 1 WHEN NVL(PEN_PREPARE_DAYS.SOURCE_ORIGIN,'2') IN ('1','2','4','3','7') and :P_HAS_PREPARE_PROTOCOLS > 0 and PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_ORGBRA_CODE = :P_APPL_UNIT_CODE and PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_YEAR = :P_APPL_YEAR and PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_NO = :P_APPL_INCR_SEQ_NO -- AYTOMATOPOIHMENES/PISTOPOIHMENOI THEN 1 ELSE 0 END GROUP BY PEN_OPS.PEN_PREPARE_DAYS.INSHISTYP_TRANS_TYPE,COM_INSURANCE_HISTORY_TYPES.TRANS_DESCR;*/
/* CHRYS 15-10-2018 SELECT B.TEXT,B.DATE_FROM,B.DATE_TO,B.EE,B.MM,B.HH FROM PEN_EFKA_DAYS_HDR A, PEN_EFKA_DAYS_DLT B WHERE A.INSURED_ID = B.INSURED_ID AND A.INSURED_ID = :P_INSURED_ID CHRYS 15/10/2018 */
SELECT PEN_OPS.PEN_PREPARE_DAYS.INSHISTYP_TRANS_TYPE, COM_INSURANCE_HISTORY_TYPES.TRANS_DESCR, COM_INSURANCE_HISTORY_TYPES.TRANS_DESCR, --TO_CHAR(MIN(TO_DATE(nvl(MONTH,12)||'/'||nvl(YEAR,4000),'MM/YYYY')),'MM/YYYY'), --TO_CHAR(MAX(TO_DATE(nvl(MONTH,1)||'/'||nvl(YEAR,1000),'MM/YYYY')),'MM/YYYY'), MIN(decode(PEN_PREPARE_DAYS.INSHISTYP_TRANS_TYPE ,'810',FROM_WORKING_DATE,'820',FROM_WORKING_DATE,'830',FROM_WORKING_DATE,'840',FROM_WORKING_DATE,TO_DATE(nvl(MONTH,12)||'/'||nvl(YEAR,4000),'MM/YYYY'))) DATE_FROM, --MAX(decode(PEN_PREPARE_DAYS.INSHISTYP_TRANS_TYPE --,'810',TO_WORKING_DATE,'820',TO_WORKING_DATE,'830',TO_WORKING_DATE,'840',TO_WORKING_DATE,TO_DATE(nvl(MONTH,1)||'/'||nvl(YEAR,1000),'MM/YYYY'))), MAX(decode(PEN_PREPARE_DAYS.INSHISTYP_TRANS_TYPE ,'810',LAST_DAY(TO_WORKING_DATE),'820',LAST_DAY(TO_WORKING_DATE),'830',LAST_DAY(TO_WORKING_DATE),'840',LAST_DAY(TO_WORKING_DATE),LAST_DAY(TO_DATE(nvl(MONTH,1)||'/'||nvl(YEAR,1000),'MM/YYYY')))) DATE_TO, SUM(nvl(NOTICE_INSURANCE_DAYS,0)+nvl(NOTICE_INS_DAYS_INCR,0)) FROM PEN_OPS.PEN_PREPARE_DAYS , COM_INSURANCE_HISTORY_TYPES, COM_COVERS_PER_COVERAGES WHERE PEN_OPS.PEN_PREPARE_DAYS.INS_INSURED_ID=:P_INSURED_ID AND PEN_OPS.PEN_PREPARE_DAYS.INSHISTYP_TRANS_TYPE=COM_INSURANCE_HISTORY_TYPES.TRANS_TYPE and COM_COVERS_PER_COVERAGES.COVCOD_COVERAGE_CODE=PEN_PREPARE_DAYS.COVCOD_COVERAGE_CODE and COM_COVERS_PER_COVERAGES.CVR_COVER_CODE IN ('ΚΣΙ', 'ΚΣΝ') AND ( nvl(NOTICE_INSURANCE_DAYS,0) != 0 OR nvl(NOTICE_INS_DAYS_INCR,0) != 0)
AND ( nvl(NOTICE_INSURANCE_DAYS,0) != 0 OR nvl(NOTICE_INS_DAYS_INCR,0) != 0) AND 1 = CASE WHEN ( ( PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_ORGBRA_CODE_DA = :P_APPL_UNIT_CODE and PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_ORGBRA_CODE_DA IS NOT NULL ) AND ( PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_YEAR_DA = :P_APPL_YEAR and PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_YEAR_DA IS NOT NULL ) AND ( PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_NO_DA = :P_APPL_INCR_SEQ_NO and PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_NO_DA IS NOT NULL ) AND NVL(PEN_PREPARE_DAYS.PARALLEL_FLG,'0') = '0' ) -- DIADOXIKI THEN 1 WHEN NVL(PEN_PREPARE_DAYS.SOURCE_ORIGIN,'2') = 2 -- AFORA PERIPTOSEIS SYGXWNEFTHENTWN APO OTHONH ATHANASIOU and PEN_PREPARE_DAYS.COMMIT_FLG = 2 THEN 1 WHEN NVL(PEN_PREPARE_DAYS.SOURCE_ORIGIN,'2') = '2' and :P_HAS_PREPARE_PROTOCOLS = 0 and PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_ORGBRA_CODE IS NULL and PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_YEAR IS NULL and PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_NO IS NULL -- AYTOMATOPOIHMENES/PISTOPOIHMENOI XVRIS PROTOCOLS THEN 1 WHEN NVL(PEN_PREPARE_DAYS.SOURCE_ORIGIN,'2') IN ('1','2','4','3','7') and :P_HAS_PREPARE_PROTOCOLS > 0 and PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_ORGBRA_CODE = :P_APPL_UNIT_CODE and PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_YEAR = :P_APPL_YEAR and PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_NO = :P_APPL_INCR_SEQ_NO -- AYTOMATOPOIHMENES/PISTOPOIHMENOI THEN 1 ELSE 0 END GROUP BY PEN_OPS.PEN_PREPARE_DAYS.INSHISTYP_TRANS_TYPE,COM_INSURANCE_HISTORY_TYPES.TRANS_DESCR;

