      function CF_28Formula return Number is
V_NUM	  NUMBER;
V_NUM_1	NUMBER;
V_NUM_2	NUMBER;

CURSOR CUR IS
SELECT ((sum(NVL(MONTH_INCOME_INFLATED,0)+NVL(RETRO_AMT_INFLATED,0))*25)/sum(NVL(MONTH_DAYS,0)))  
FROM PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR; 

CURSOR CUR_1 IS
SELECT   NVL(POSOSTO_ANAPL,0)+ NVL(ADAPOD_PERCENT_KSB,0)
FROM  PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR;

CURSOR CUR_2 IS
SELECT  DISTINCT AVERAGE_INCOME
		-- CHRYS 27/3/2024((sum(NVL(MONTH_INCOME_INFLATED,0)+NVL(RETRO_AMT_INFLATED,0))*25)/sum(NVL(MONTH_DAYS,0)))  
FROM PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR; 


begin
  
  OPEN CUR;
  FETCH CUR 
  INTO V_NUM;
  CLOSE CUR;
  
  
  OPEN CUR_1;
  FETCH CUR_1 
  INTO V_NUM_1;
  CLOSE CUR_1;
  
  OPEN CUR_2;
  FETCH CUR_2 
  INTO V_NUM_2;
  CLOSE CUR_2;
  
  IF V_NUM_2 IS NOT NULL THEN
  	V_NUM := V_NUM_2;	
  END IF;
  
  RETURN (NVL(V_NUM,0)*NVL(V_NUM_1,0))/100;
  
EXCEPTION
	WHEN OTHERS THEN
	RETURN NULL;
end;

