function AfterPForm return boolean is
CURSOR C1 IS SELECT COM_ORG_BRANCHES.BRANCH_NAME, COM_ORG_BRANCHES.BRANCH_CODE FROM REG_INSURED, PEN_APPLICATION_INSTANCES, COM_ORG_BRANCHES, PEN_BE_PER_PRODINST, PEN_PRODUCT_PER_INSTITUTIONS, PEN_PRODUCTS, COM_PENSION_IKA_INSTITUTION WHERE PEN_APPLICATION_INSTANCES.APPLICATION_INCR_SEQ_NO=:P_APPL_INCR_SEQ_NO AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_UNIT_CODE=:P_APPL_UNIT_CODE AND PEN_APPLICATION_INSTANCES.PDTA_DOCUMENT_TYPE_APPL_CODE='00001' AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_YEAR=:P_APPL_YEAR AND PEN_APPLICATION_INSTANCES.INSURED_ID=:P_INSURED_ID AND REG_INSURED.INSURED_ID=PEN_APPLICATION_INSTANCES.INSURED_ID AND PEN_BE_PER_PRODINST.BE_PER_PRODINST_CODE=:P_BE_PER_PRODINST AND PEN_BE_PER_PRODINST.PRODUCT_PER_INSTITUTION_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_PER_INSTITUTION_CODE AND COM_PENSION_IKA_INSTITUTION.PENSION_IKA_INST_CODE=PEN_PRODUCT_PER_INSTITUTIONS.INSTITUTION_CODE AND PEN_PRODUCTS.PRODUCT_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_CODE AND COM_ORG_BRANCHES.BRANCH_CODE=:P_DT_DEC_UNIT_CODE_SR;
---- pollaples thanatou TSAY-TSMEDE ktl. (NT - 16/11/2020) cursor c2 is SELECT VALUE --- (ΝΑΙ=1,ΟΧΙ=0,ΔΕΝ ΑΦΟΡΑ=2) FROM PEN_DEC_FACT_TYPES_INSTANCE WHERE 1=1 AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_INCR_SEQ_NO_SR = :P_DT_INCR_SEC_NO_DIR AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_DIR AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_DIR AND PEN_DEC_FACT_TYPES_INSTANCE.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' AND PEN_DEC_FACT_TYPES_INSTANCE.INS_INSURED_ID = :P_INSURED_ID AND PEN_DEC_FACT_TYPES_INSTANCE.TITLE_CODE = '00661' --ΠΟΛΛΑΠΛΗ ΘΑΝΑΤΟΥ AND PEN_DEC_FACT_TYPES_INSTANCE.DEC_FACT_TYPE_CODE = '00809' --ΠΟΛΛΑΠΛΗ ΘΑΝΑΤΟΥ ;
l_pollapli_thanatou varchar2(12);
cursor c_prep_Days is ---ΕΛΕΓΧΟΣ ΑΝ ΕΧΕΙ ΠΡΩΤΟΚΟΛΛΑ -ΑΝ ΝΑΙ ΝΑ ΤΑ ΕΛΕΓΧΕΙ ΑΝ ΟΧΙ ΝΑ ΠΑΙΖΕΙ ΜΕ ΤΟ NULL SELECT COUNT(1) FROM PEN_OPS.PEN_PREPARE_DAYS , COM_INSURANCE_HISTORY_TYPES, COM_COVERS_PER_COVERAGES WHERE PEN_OPS.PEN_PREPARE_DAYS.INS_INSURED_ID = :P_INSURED_ID AND PEN_OPS.PEN_PREPARE_DAYS.INSHISTYP_TRANS_TYPE = COM_INSURANCE_HISTORY_TYPES.TRANS_TYPE AND COM_COVERS_PER_COVERAGES.COVCOD_COVERAGE_CODE = PEN_PREPARE_DAYS.COVCOD_COVERAGE_CODE AND COM_COVERS_PER_COVERAGES.CVR_COVER_CODE IN ('ΚΣΙ', 'ΚΣΝ') AND ( nvl(NOTICE_INSURANCE_DAYS,0) != 0 OR nvl(NOTICE_INS_DAYS_INCR,0) != 0) AND NVL(PEN_PREPARE_DAYS.SOURCE_ORIGIN,'2') = '2' AND PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_ORGBRA_CODE = :P_APPL_UNIT_CODE AND PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_YEAR = :P_APPL_YEAR AND PEN_OPS.PEN_PREPARE_DAYS.PROTOCOL_NO = :P_APPL_INCR_SEQ_NO ;
-------------- BEGIN
begin OPEN C1; FETCH C1 INTO :P_BRANCH_NAME, :P_BRANCH_CODE; CLOSE C1;
open c2; fetch c2 into l_pollapli_thanatou; close c2;
if nvl(l_pollapli_thanatou,'0') = '1' then :P_POLLAPLI_THANATOU := 1; else :P_POLLAPLI_THANATOU := 0; end if;
-- EΛΕΓΧΟΣ ΓΙΑ ΧΡΟΝΟΥΣ ΣΤΟΝ PREPARE DAYS open c_prep_Days; fetch c_prep_Days into :P_HAS_PREPARE_PROTOCOLS; close c_prep_Days;
return (TRUE); end;

