      function CF_135Formula return Char is

V_CHAR	VARCHAR2(5);

CURSOR	CUR_1 IS
SELECT 	A.INTRODUCTION_CODE
FROM 		PEN_PRODUCT_PER_INSTITUTIONS A
		 	 ,PEN_QC_PER_PRODINST B
		   ,PEN_ACCOUNT C
WHERE 	C.ACCOUNT_NO = :P_ACC_ACCOUNT_NO 
AND 		B.QC_PER_PRODINST_CODE=C.QCPRODINS_QC_PER_PRODINST_CODE
AND			B.PRODUCT_PER_INSTITUTION_CODE=A.PRODUCT_PER_INSTITUTION_CODE;

begin
  
 
  OPEN CUR_1;
