  function CF_AVERAGE_INCOME2Formula return Number is

CURSOR CUR_AVERAGE_INCOME IS
SELECT DISTINCT AVERAGE_INCOME
FROM PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR;

V_AVERAGE_INCOME		NUMBER;
begin
OPEN 	  CUR_AVERAGE_INCOME;
FETCH	CUR_AVERAGE_INCOME
INTO	V_AVERAGE_INCOME;
CLOSE	CUR_AVERAGE_INCOME;

IF V_AVERAGE_INCOME IS NOT NULL THEN
	RETURN(V_AVERAGE_INCOME);
ELSE
	RETURN(:INFLATED_3);
END IF;
end;

